/**
 * moodPrototypes.js
 *
 * Mood prototype embeddings learned from real songs via YAMNet.
 * Each array below is the mean YAMNet embedding (1024 values) for one song.
 *
 * HOW TO FILL THESE IN:
 *   1. Play a 20-30 second section of the song.
 *   2. The browser console will print "Mean embedding: [...]".
 *   3. Copy that array and paste it here, replacing the placeholder zeros.
 *
 * Training song list (4 moods × 5 songs = 20 songs):
 *
 * Aggressive  — high distortion, strong bass, high rhythmic intensity
 *   FE!N — Travis Scott
 *   DNA — Kendrick Lamar
 *   Black Skinhead — Kanye West
 *   SICKO MODE — Travis Scott
 *   HUMBLE — Kendrick Lamar
 *
 * Energetic   — fast tempo, bright instruments, high rhythmic energy
 *   Blinding Lights — The Weeknd
 *   Titanium — David Guetta
 *   Don't Start Now — Dua Lipa
 *   Can't Stop — Red Hot Chili Peppers
 *   Uptown Funk — Bruno Mars
 *
 * Chill       — soft vocals, low percussion intensity, stable dynamics
 *   Perfect — Ed Sheeran
 *   Location — Khalid
 *   Sunset Lover — Petit Biscuit
 *   Pink + White — Frank Ocean
 *   Let Her Go — Passenger
 *
 * Dark        — low brightness, heavy bass, slow mood
 *   After Hours — The Weeknd
 *   Royals — Lorde
 *   Bury a Friend — Billie Eilish
 *   Runaway — Kanye West
 *   Lovely — Billie Eilish
 */

// ─── Helper ──────────────────────────────────────────────────────────────────

/**
 * Averages an array of 1024-dim vectors into a single prototype center.
 * @param {number[][]} vectors - Array of embedding arrays.
 * @returns {number[]} - Averaged prototype vector.
 */
export function computePrototype(vectors) {
  const length = vectors[0].length;
  return Array.from({ length }, (_, i) =>
    vectors.reduce((sum, v) => sum + v[i], 0) / vectors.length
  );
}

